+        shard.slots.push(slot1);
+        let slot1_idx = shard.slots.len() - 1;
+        shard.addr_to_slot.insert(user1, slot1_idx);
+        shard.quarantine.push_back(QuarantineEntry {
+            user_base: user1,
+            raw_base: raw1,
+            total_size,
+            align,
